const nav=document.getElementById("nav");const burger=document.getElementById("burger");if(burger&&nav){nav.classList.add("nav-hidden");burger.addEventListener("click",()=>{if(nav.classList.contains("nav-hidden")){nav.classList.remove("nav-hidden");burger.setAttribute("aria-expanded","true")}else{nav.classList.add("nav-hidden");burger.setAttribute("aria-expanded","false")}});nav.addEventListener("keydown",event=>{if(event.key==="Escape"){nav.classList.add("nav-hidden");burger.setAttribute("aria-expanded","false");burger.focus()}})}class LiWithSubnav{#li=null;#button=null;#ul=null;constructor(li){this.#li=li;this.#ul=this.#li.querySelector(":scope > ul");this.createButton();this.#button.addEventListener("click",e=>{e.stopPropagation();if(this.#li.classList.contains("subnav-visible")){this.collapse(true)}else{this.expand();const firstLink=this.#ul.querySelector(":scope > li:first-child > a");if(firstLink)firstLink.focus()}});this.#ul.addEventListener("keydown",event=>{if(event.key==="Escape"){event.stopPropagation();this.collapse(true)}});this.#ul.addEventListener("focusout",event=>{if(!this.#li.contains(event.relatedTarget)){this.collapse()}})}expand(){this.#li.classList.add("subnav-visible");this.#button.setAttribute("aria-expanded","true")}collapse(focus=false){this.#li.classList.remove("subnav-visible");this.#button.setAttribute("aria-expanded","false");if(focus)this.#button.focus()}createButton(){const button=document.createElement("button");const iconDown=document.createElement("span");const iconUp=document.createElement("span");iconDown.classList.add("bx","bx-chevron-down","icon-down");iconUp.classList.add("bx","bx-chevron-up","icon-up");iconDown.setAttribute("aria-label","Afficher le sous-menu");iconUp.setAttribute("aria-label","Masquer le sous-menu");button.append(iconDown,iconUp);button.setAttribute("aria-expanded","false");button.setAttribute("aria-controls",this.#ul.id);this.#li.classList.add("has-subnav");this.#li.insertBefore(button,this.#ul);this.#button=button}}document.querySelectorAll("#nav li:has(> ul)").forEach(li=>{const ul=li.querySelector(":scope > ul");if(!ul.id){ul.id="subnav-"+Math.random().toString(36).slice(2,7)}new LiWithSubnav(li)});const modal=document.getElementById("modal");const openBtn=document.getElementById("open-modal");const closeBtns=document.querySelectorAll(".modal-close, #modal-action");const FOCUSABLE='a[href], button:not([disabled]), input, select, textarea, [tabindex]:not([tabindex="-1"])';function openModal(){modal.setAttribute("aria-hidden","false");modal.classList.add("modal-visible");document.body.classList.add("modal-open");const firstFocusable=modal.querySelector(FOCUSABLE);if(firstFocusable)firstFocusable.focus()}function closeModal(){modal.setAttribute("aria-hidden","true");modal.classList.remove("modal-visible");document.body.classList.remove("modal-open");if(openBtn)openBtn.focus()}if(openBtn&&modal){openBtn.addEventListener("click",openModal);closeBtns.forEach(btn=>{btn.addEventListener("click",closeModal)});modal.addEventListener("click",event=>{if(event.target===modal)closeModal()});modal.addEventListener("keydown",event=>{if(event.key==="Escape")closeModal()});modal.addEventListener("keydown",event=>{if(event.key!=="Tab")return;const focusables=[...modal.querySelectorAll(FOCUSABLE)];if(focusables.length===0)return;const first=focusables[0];const last=focusables[focusables.length-1];if(event.shiftKey&&document.activeElement===first){event.preventDefault();last.focus()}else if(!event.shiftKey&&document.activeElement===last){event.preventDefault();first.focus()}})}const REGEX={name:/^[a-zA-ZÀ-ÿ\-' ]{2,50}$/,email:/^[^\s@]+@[^\s@]+\.[^\s@]{2,}$/,message:/^[\s\S]{10,1000}$/};const MESSAGES={firstname:{valueMissing:"Le prénom est obligatoire.",patternError:"Prénom invalide (2–50 lettres)."},lastname:{valueMissing:"Le nom est obligatoire.",patternError:"Nom invalide (2–50 lettres)."},email:{valueMissing:"L'adresse email est obligatoire.",patternError:"Email invalide. Exemple : nom@domaine.fr"},sujet:{valueMissing:"Veuillez choisir un sujet."},message:{valueMissing:"Le message est obligatoire.",patternError:"Le message doit contenir entre 10 et 1000 caractères."}};function showError(input,message){const group=input.closest(".form-group");if(!group)return;group.classList.add("error");group.classList.remove("success");let el=group.querySelector(".error-message");if(!el){el=document.createElement("p");el.classList.add("error-message");el.setAttribute("role","alert");el.id="err-"+input.id;input.insertAdjacentElement("afterend",el)}el.textContent=message;input.setAttribute("aria-invalid","true");input.setAttribute("aria-describedby",el.id)}function showSuccess(input){const group=input.closest(".form-group");if(!group)return;group.classList.remove("error");group.classList.add("success");group.querySelector(".error-message")?.remove();input.removeAttribute("aria-invalid");input.removeAttribute("aria-describedby")}function clearState(input){const group=input.closest(".form-group");if(!group)return;group.classList.remove("error","success");group.querySelector(".error-message")?.remove();input.removeAttribute("aria-invalid")}function validateField(input){const name=input.name;const value=input.value.trim();if(input.required&&!value){showError(input,MESSAGES[name]?.valueMissing||"Ce champ est obligatoire.");return false}if(value&&REGEX[name]&&!REGEX[name].test(value)){showError(input,MESSAGES[name]?.patternError||"Valeur invalide.");return false}if(value)showSuccess(input);else clearState(input);return true}const textarea=document.getElementById("message");const charCount=document.getElementById("char-count");const charCounter=document.querySelector(".char-counter");if(textarea&&charCount){textarea.addEventListener("input",()=>{const len=textarea.value.length;charCount.textContent=len;charCounter?.classList.toggle("over-limit",len>1e3)})}const form=document.getElementById("contact-form");if(form){form.querySelectorAll("input:not([name='_gotcha']), select, textarea").forEach(input=>{input.addEventListener("blur",()=>{if(input.value.trim()||input.required)validateField(input)});input.addEventListener("input",()=>{const formGroup=input.closest(".form-group");if(formGroup&&formGroup.classList.contains("error")){validateField(input)}});if(input.tagName==="SELECT"){input.addEventListener("change",()=>validateField(input))}});let lastSubmit=0;form.addEventListener("submit",async e=>{e.preventDefault();if(form.querySelector("input[name='_gotcha']")?.value)return;if(Date.now()-lastSubmit<5e3)return;let hasError=false;form.querySelectorAll("input[required], select[required], textarea[required]").forEach(input=>{if(!validateField(input))hasError=true});if(hasError){form.querySelector(".form-group.error input, .form-group.error select, .form-group.error textarea")?.focus();return}const btn=form.querySelector(".btn-submit-contact");const btnText=btn.querySelector(".btn-text");btn.disabled=true;btnText.textContent="Envoi en cours...";document.getElementById("form-success")?.setAttribute("hidden","");document.getElementById("form-error")?.setAttribute("hidden","");try{const response=await fetch(form.action,{method:"POST",body:new FormData(form),headers:{Accept:"application/json"}});if(response.ok){lastSubmit=Date.now();form.hidden=true;const success=document.getElementById("form-success");if(success){success.removeAttribute("hidden");success.focus()}}else{throw new Error("HTTP "+response.status)}}catch(err){console.error("Erreur envoi :",err);btn.disabled=false;btnText.textContent="Envoyer le message";document.getElementById("form-error")?.removeAttribute("hidden")}})}